// Per-deskmate avatar images, base64-encoded PNG, served by
// agent/channels/deskmate-avatars.ts and referenced as each deskmate's Slack
// `icon_url`. Bundling the bytes here (rather than a static dir or an external
// host) keeps avatars self-contained: a fork deploys and the pictures just work.
//
// To replace a deskmate's picture with your own, drop a square PNG's base64 here
// under its id (or point icon_url at a hosted image). Keep them small — they ship
// in the function bundle. Defaults: the role emoji on a branded gradient (128×128).

export const AVATARS: Record<string, string> = {
  devops:
    "",
  product_analyst:
    "",
};

export function hasAvatar(id: string): boolean {
  return typeof AVATARS[id] === "string" && AVATARS[id].length > 0;
}

export function avatarPng(id: string): Uint8Array | null {
  const b64 = AVATARS[id];
  if (!b64) return null;
  return Uint8Array.from(Buffer.from(b64, "base64"));
}
